public sealed class EventOfflineCheckinService : IDisposable
{
    private const int ReplayWindow=15, BatchMax=500; private static readonly HashSet<string> Operations=["check_in","check_out","no_show","undo"];
    private readonly NexusDbContext _db; private readonly Key _signingKey; private readonly string _kid; private readonly string _publicKey;
    public EventOfflineCheckinService(NexusDbContext db,IConfiguration config)
    {
        _db=db; var material=config["Jwt:Key"]??config["Jwt:Secret"]??"nexus-local-event-checkin-signing-boundary";
        var seed=SHA256.HashData(Encoding.UTF8.GetBytes(material+"|event-checkin-ed25519-v2"));
        _signingKey=Key.Import(SignatureAlgorithm.Ed25519,seed,KeyBlobFormat.RawPrivateKey);
