    }
    public void Dispose()=>_signingKey.Dispose();

    public async Task<EventOfflineResult> WorkspaceAsync(int tenant,int eventId,int actor,CancellationToken ct)
    {
        var c=await Context(tenant,eventId,actor,true,ct);if(!c.Succeeded)return c;var e=(Event)c.Data!;
        var devices=await _db.EventCheckinDevices.IgnoreQueryFilters().AsNoTracking().Where(x=>x.TenantId==tenant&&x.EventId==eventId).OrderByDescending(x=>x.Id).Take(50).ToListAsync(ct);
        var batches=await _db.EventOfflineSyncBatches.IgnoreQueryFilters().AsNoTracking().Where(x=>x.TenantId==tenant&&x.EventId==eventId).OrderByDescending(x=>x.Id).Take(50).ToListAsync(ct);
        var ids=batches.Select(x=>x.Id).ToArray();var decisions=await _db.EventOfflineSyncDecisions.IgnoreQueryFilters().AsNoTracking().Where(x=>x.TenantId==tenant&&ids.Contains(x.BatchId)).ToListAsync(ct);
        var open=await OpenQuery(tenant,eventId).CountAsync(ct);
        return new(new{contract_version=1,event_id=eventId,occurrence_key=Occurrence(e),manifest_version=e.CheckinManifestVersion,limits=new{replay_window_minutes=ReplayWindow,batch_max_items=BatchMax},devices=devices.Select(Device),recent_batches=batches.Select(x=>BatchSummary(x,decisions.Where(d=>d.BatchId==x.Id))),open_conflicts=open,permissions=new{manage_devices=true,download_manifest=true,sync_offline_queue=true,resolve_conflicts=true,manual_fallback_required=true},privacy=new{device_secrets_redacted=true,credential_secrets_redacted=true,contact_fields_redacted=true,wallet_effects_supported=false}});
    }
    public async Task<EventOfflineResult> MyCredentialAsync(int tenant,int eventId,int actor,CancellationToken ct)
    {
        var c=await Context(tenant,eventId,actor,false,ct);if(!c.Succeeded)return c;var reg=await ConfirmedRegistration(tenant,eventId,actor,ct);if(reg is null)return Missing("EVENT_CHECKIN_REGISTRATION_NOT_FOUND");
        var row=await _db.EventCheckinCredentials.IgnoreQueryFilters().AsNoTracking().Where(x=>x.TenantId==tenant&&x.EventId==eventId&&x.RegistrationId==reg.Id).OrderByDescending(x=>x.CredentialVersion).FirstOrDefaultAsync(ct);
        return new(new{contract_version=1,event_id=eventId,credential=row is null?null:Credential(row,null,false)});
    }
    public async Task<EventOfflineResult> IssueCredentialAsync(int tenant,int eventId,int actor,long? registrationId,string key,CancellationToken ct)
    {
        var k=ValidKey(key);if(k is not null)return k;await using var tx=await _db.Database.BeginTransactionAsync(ct);await Lock(tenant,eventId,ct);var c=await Context(tenant,eventId,actor,false,ct);if(!c.Succeeded)return c;var e=(Event)c.Data!;
        var reg=registrationId is long id?await _db.EventRegistrations.IgnoreQueryFilters().SingleOrDefaultAsync(x=>x.TenantId==tenant&&x.EventId==eventId&&x.Id==id&&x.RegistrationState=="confirmed",ct):await ConfirmedRegistration(tenant,eventId,actor,ct);if(reg is null)return Missing("EVENT_CHECKIN_REGISTRATION_NOT_FOUND");if(reg.UserId!=actor&&!await CanManage(tenant,e,actor,ct))return Forbidden();
        var kh=Hash(key);var replay=await _db.EventCheckinCredentials.IgnoreQueryFilters().SingleOrDefaultAsync(x=>x.TenantId==tenant&&x.IssueIdempotencyHash==kh,ct);if(replay is not null){if(replay.EventId!=eventId||replay.RegistrationId!=reg.Id||replay.IssuedByUserId!=actor)return Conflict("EVENT_CHECKIN_IDEMPOTENCY_CONFLICT");await tx.CommitAsync(ct);return CredentialResult(eventId,replay,null,e.CheckinManifestVersion,200);}
        var active=await _db.EventCheckinCredentials.IgnoreQueryFilters().AnyAsync(x=>x.TenantId==tenant&&x.RegistrationId==reg.Id&&x.Status=="active"&&x.ExpiresAt>DateTime.UtcNow,ct);if(active)return Conflict("EVENT_CHECKIN_CREDENTIAL_ACTIVE_EXISTS");
        var version=(await _db.EventCheckinCredentials.IgnoreQueryFilters().Where(x=>x.TenantId==tenant&&x.RegistrationId==reg.Id).MaxAsync(x=>(int?)x.CredentialVersion,ct)??0)+1;var expiry=Expiry(e);var token=SignedCredential(tenant,e,version,expiry);var row=new EventCheckinCredential{TenantId=tenant,EventId=eventId,RegistrationId=reg.Id,UserId=reg.UserId,CredentialVersion=version,TokenHash=Hash(token),TokenFingerprint=Hash(token)[..16],IssueIdempotencyHash=kh,IssuedByUserId=actor,ExpiresAt=expiry};_db.EventCheckinCredentials.Add(row);e.CheckinManifestVersion++;await _db.SaveChangesAsync(ct);await tx.CommitAsync(ct);return CredentialResult(eventId,row,token,e.CheckinManifestVersion,201);
    }
    public async Task<EventOfflineResult> RotateCredentialAsync(int tenant,int eventId,long id,int actor,int expected,string key,CancellationToken ct)
    {
        var valid=ValidKey(key);if(valid is not null)return valid;await using var tx=await _db.Database.BeginTransactionAsync(ct);await Lock(tenant,eventId,ct);var c=await Context(tenant,eventId,actor,false,ct);if(!c.Succeeded)return c;var e=(Event)c.Data!;var old=await _db.EventCheckinCredentials.IgnoreQueryFilters().SingleOrDefaultAsync(x=>x.TenantId==tenant&&x.EventId==eventId&&x.Id==id,ct);if(old is null)return Missing();if(old.UserId!=actor&&!await CanManage(tenant,e,actor,ct))return Forbidden();var kh=Hash(key);var replay=await _db.EventCheckinCredentials.IgnoreQueryFilters().SingleOrDefaultAsync(x=>x.TenantId==tenant&&x.IssueIdempotencyHash==kh,ct);if(replay is not null){if(old.SupersededById!=replay.Id||old.CredentialVersion!=expected)return Conflict("EVENT_CHECKIN_IDEMPOTENCY_CONFLICT");await tx.CommitAsync(ct);return CredentialResult(eventId,replay,null,e.CheckinManifestVersion,200);}if(old.CredentialVersion!=expected||old.Status!="active")return Conflict();var expiry=Expiry(e);var token=SignedCredential(tenant,e,expected+1,expiry);var next=new EventCheckinCredential{TenantId=tenant,EventId=eventId,RegistrationId=old.RegistrationId,UserId=old.UserId,CredentialVersion=expected+1,TokenHash=Hash(token),TokenFingerprint=Hash(token)[..16],IssueIdempotencyHash=kh,IssuedByUserId=actor,ExpiresAt=expiry};old.Status="rotated";old.RotatedAt=DateTime.UtcNow;old.UpdatedAt=DateTime.UtcNow;_db.Add(next);await _db.SaveChangesAsync(ct);old.SupersededById=next.Id;e.CheckinManifestVersion++;await _db.SaveChangesAsync(ct);await tx.CommitAsync(ct);return CredentialResult(eventId,next,token,e.CheckinManifestVersion,201);
    }
    public async Task<EventOfflineResult> RevokeCredentialAsync(int tenant,int eventId,long id,int actor,int expected,string? reason,CancellationToken ct)
    {var clean=Clean(reason,500);if(clean is null)return Validation("reason");await using var tx=await _db.Database.BeginTransactionAsync(ct);await Lock(tenant,eventId,ct);var c=await Context(tenant,eventId,actor,false,ct);if(!c.Succeeded)return c;var e=(Event)c.Data!;var row=await _db.EventCheckinCredentials.IgnoreQueryFilters().SingleOrDefaultAsync(x=>x.TenantId==tenant&&x.EventId==eventId&&x.Id==id,ct);if(row is null)return Missing();if(row.UserId!=actor&&!await CanManage(tenant,e,actor,ct))return Forbidden();if(row.CredentialVersion!=expected)return Conflict();if(row.Status!="revoked"){if(row.Status!="active")return Conflict();row.Status="revoked";row.RevokedByUserId=actor;row.RevokedAt=DateTime.UtcNow;row.RevocationReason=clean;row.UpdatedAt=DateTime.UtcNow;e.CheckinManifestVersion++;await _db.SaveChangesAsync(ct);}await tx.CommitAsync(ct);return CredentialResult(eventId,row,null,e.CheckinManifestVersion,200);}

