    public async Task<EventOfflineResult> RotateDeviceAsync(int tenant,int eventId,long id,int actor,int expected,string key,CancellationToken ct)
    {var valid=ValidKey(key);if(valid is not null)return valid;await using var tx=await _db.Database.BeginTransactionAsync(ct);await Lock(tenant,eventId,ct);var c=await Context(tenant,eventId,actor,true,ct);if(!c.Succeeded)return c;var e=(Event)c.Data!;var row=await _db.EventCheckinDevices.IgnoreQueryFilters().SingleOrDefaultAsync(x=>x.TenantId==tenant&&x.EventId==eventId&&x.Id==id,ct);if(row is null)return Missing();var kh=Hash(key);if(row.LastRotationIdempotencyHash==kh){await tx.CommitAsync(ct);return DeviceResult(eventId,row,null,e.CheckinManifestVersion,200);}if(row.DeviceVersion!=expected||row.Status!="active")return Conflict();var secret=Secret("nxd1_");row.SecretHash=Hash(secret);row.SecretFingerprint=row.SecretHash[..16];row.DeviceVersion++;row.LastRotationIdempotencyHash=kh;row.RotatedAt=DateTime.UtcNow;row.UpdatedAt=DateTime.UtcNow;e.CheckinManifestVersion++;await _db.SaveChangesAsync(ct);await tx.CommitAsync(ct);return DeviceResult(eventId,row,secret,e.CheckinManifestVersion,200);}
