    public async Task<EventOfflineResult> ManifestAsync(int tenant,int eventId,int actor,string secret,int? ttl,CancellationToken ct)
    {var c=await Context(tenant,eventId,actor,true,ct);if(!c.Succeeded)return c;var e=(Event)c.Data!;var device=await DeviceBySecret(tenant,eventId,secret,ct);if(device is null)return UnauthorizedDevice();var minutes=Math.Clamp(ttl??120,5,720);var regs=await _db.EventRegistrations.IgnoreQueryFilters().AsNoTracking().Where(x=>x.TenantId==tenant&&x.EventId==eventId&&x.RegistrationState=="confirmed").ToListAsync(ct);var ids=regs.Select(x=>x.Id).ToArray();var creds=await _db.EventCheckinCredentials.IgnoreQueryFilters().AsNoTracking().Where(x=>x.TenantId==tenant&&x.EventId==eventId&&ids.Contains(x.RegistrationId)&&x.Status=="active"&&x.ExpiresAt>DateTime.UtcNow).ToListAsync(ct);var users=await _db.Users.IgnoreQueryFilters().AsNoTracking().Where(x=>x.TenantId==tenant&&regs.Select(r=>r.UserId).Contains(x.Id)).ToDictionaryAsync(x=>x.Id,ct);var attendance=await _db.EventAttendance.IgnoreQueryFilters().AsNoTracking().Where(x=>x.TenantId==tenant&&x.EventId==eventId).ToDictionaryAsync(x=>x.UserId,ct);var now=DateTime.UtcNow;var rows=creds.Join(regs,x=>x.RegistrationId,x=>x.Id,(x,r)=>(x,r)).Select(z=>new{registration_id=z.r.Id,user_id=z.r.UserId,display_name=users.TryGetValue(z.r.UserId,out var u)?Name(u):"",credential_version=z.x.CredentialVersion,credential_fingerprint=z.x.TokenFingerprint,credential_verifier=z.x.TokenHash,attendance_status=attendance.TryGetValue(z.r.UserId,out var a)?a.AttendanceStatus:null,attendance_version=attendance.TryGetValue(z.r.UserId,out a)?a.AttendanceVersion:0});return new(new{schema_version=2,tenant_id=tenant,event_id=eventId,occurrence_key=Occurrence(e),manifest_version=e.CheckinManifestVersion,device=new{id=device.Id,version=device.DeviceVersion},generated_at=Iso(now),expires_at=Iso(now.AddMinutes(minutes)),credential_verification=new{format="nqx2",algorithm="Ed25519",keys=new[]{new{kid=_kid,alg="Ed25519",public_key=_publicKey}}},registrations=rows,privacy=new{credential_contains_pii=false,encrypted_at_rest_required=true}});}

    public async Task<EventOfflineResult> StageAsync(int tenant,int eventId,int actor,JsonElement body,CancellationToken ct)
    {
        if(!TryText(body,"device_secret",out var secret)||!TryText(body,"client_batch_id",out var clientId)||clientId.Length>191||!body.TryGetProperty("manifest_version",out var mv)||!mv.TryGetInt64(out var manifest)||!body.TryGetProperty("items",out var raw)||raw.ValueKind!=JsonValueKind.Array||raw.GetArrayLength()<1||raw.GetArrayLength()>BatchMax)return Validation("items");
        var device=await DeviceBySecret(tenant,eventId,secret,ct);if(device is null)return UnauthorizedDevice();
        var c=await Context(tenant,eventId,actor,true,ct);if(!c.Succeeded)return c;
        var payload=Hash(body.GetRawText());
        var replay=await _db.EventOfflineSyncBatches.IgnoreQueryFilters().SingleOrDefaultAsync(x=>x.TenantId==tenant&&x.DeviceId==device.Id&&x.ClientBatchId==clientId,ct);
        if(replay is not null){if(replay.PayloadHash!=payload)return Conflict("EVENT_CHECKIN_BATCH_IDEMPOTENCY_CONFLICT");return await BatchAsync(tenant,eventId,replay.Id,actor,ct);}

        var inputs=new List<EventOfflineSyncItem>();var pos=0;
        foreach(var x in raw.EnumerateArray())
        {
            pos++;
            if(!TryText(x,"client_nonce",out var nonce)||nonce.Length<8||nonce.Length>191||!TryText(x,"operation",out var op)||!Operations.Contains(op)||!TryDate(x,"observed_at",out var observed)||!TryLong(x,"expected_attendance_version",out var expected)||expected<0||!TryText(x,"credential_fingerprint",out var fp)||!Regex.IsMatch(fp,"^[0-9a-f]{16}$")||!TryText(x,"credential_hash_reference",out var href)||!Regex.IsMatch(href,"^[0-9a-f]{64}$")||!href.StartsWith(fp,StringComparison.Ordinal)||inputs.Any(i=>i.ClientNonce==nonce))return Validation("items");
            inputs.Add(new(){TenantId=tenant,EventId=eventId,DeviceId=device.Id,Position=pos,ClientNonce=nonce,Operation=op,ObservedAt=observed,ExpectedAttendanceVersion=expected,CredentialFingerprint=fp,CredentialHashReference=href,Reason=Clean(Text(x,"reason"),500)});
        }

        await using var tx=await _db.Database.BeginTransactionAsync(ct);
        await Lock(tenant,eventId,ct);
        var credentialEvaluatedAt=DateTime.UtcNow;
        var credentials=await ResolveCredentialSubjects(tenant,eventId,inputs,credentialEvaluatedAt,ct);
        var batch=new EventOfflineSyncBatch{TenantId=tenant,EventId=eventId,DeviceId=device.Id,SubmittedByUserId=actor,ClientBatchId=clientId,PayloadHash=payload,ManifestVersion=manifest,ItemCount=inputs.Count,Status="processing"};
        _db.Add(batch);await _db.SaveChangesAsync(ct);
        foreach(var item in inputs){item.BatchId=batch.Id;_db.Add(item);}
        await _db.SaveChangesAsync(ct);
        foreach(var item in inputs)
        {
            credentials.TryGetValue(item.CredentialFingerprint,out var credential);
            await DecideInitial(tenant,eventId,actor,item,credential,credentialEvaluatedAt,ct);
        }
        var ds=await _db.EventOfflineSyncDecisions.IgnoreQueryFilters().Where(x=>x.TenantId==tenant&&x.BatchId==batch.Id).ToListAsync(ct);
        batch.AcceptedCount=ds.Count(x=>x.Outcome=="accepted");batch.ConflictCount=ds.Count(x=>x.Outcome=="conflict");batch.RejectedCount=ds.Count(x=>x.Outcome=="rejected");batch.Status="completed";batch.CompletedAt=DateTime.UtcNow;
        await _db.SaveChangesAsync(ct);await tx.CommitAsync(ct);
        var result=await BatchAsync(tenant,eventId,batch.Id,actor,ct);return result with{Status=202};
    }
    public async Task<EventOfflineResult> BatchAsync(int tenant,int eventId,long id,int actor,CancellationToken ct){var c=await Context(tenant,eventId,actor,true,ct);if(!c.Succeeded)return c;var batch=await _db.EventOfflineSyncBatches.IgnoreQueryFilters().AsNoTracking().SingleOrDefaultAsync(x=>x.TenantId==tenant&&x.EventId==eventId&&x.Id==id,ct);if(batch is null)return Missing();var items=await _db.EventOfflineSyncItems.IgnoreQueryFilters().AsNoTracking().Where(x=>x.TenantId==tenant&&x.BatchId==id).OrderBy(x=>x.Position).ToListAsync(ct);var decisions=await _db.EventOfflineSyncDecisions.IgnoreQueryFilters().AsNoTracking().Where(x=>x.TenantId==tenant&&x.BatchId==id).ToListAsync(ct);return BatchResult(eventId,batch,items,decisions);}
    public async Task<EventOfflineResult> ConflictsAsync(int tenant,int eventId,int actor,int page,CancellationToken ct){var c=await Context(tenant,eventId,actor,true,ct);if(!c.Succeeded)return c;page=Math.Max(1,page);var all=await OpenQuery(tenant,eventId).ToListAsync(ct);var total=all.Count;var rows=all.OrderByDescending(x=>x.Decision.DecidedAt).Skip((page-1)*25).Take(25).ToList();var users=await _db.Users.IgnoreQueryFilters().AsNoTracking().Where(x=>x.TenantId==tenant).ToDictionaryAsync(x=>x.Id,ct);var devices=await _db.EventCheckinDevices.IgnoreQueryFilters().AsNoTracking().Where(x=>x.TenantId==tenant&&x.EventId==eventId).ToDictionaryAsync(x=>x.Id,ct);var attendance=await _db.EventAttendance.IgnoreQueryFilters().AsNoTracking().Where(x=>x.TenantId==tenant&&x.EventId==eventId).ToDictionaryAsync(x=>x.UserId,ct);return ConflictResult(eventId,rows,total,page,users,devices,attendance);}
    public async Task<EventOfflineResult> ResolveAsync(int tenant,int eventId,long itemId,int actor,int expectedDecision,string disposition,long expectedAttendance,string? reason,string key,CancellationToken ct)
    {if(disposition is not ("apply" or "reject")||expectedDecision<1||expectedAttendance<0||Clean(reason,500) is not string clean)return Validation("resolution");var valid=ValidKey(key);if(valid is not null)return valid;await using var tx=await _db.Database.BeginTransactionAsync(ct);await Lock(tenant,eventId,ct);var c=await Context(tenant,eventId,actor,true,ct);if(!c.Succeeded)return c;var item=await _db.EventOfflineSyncItems.IgnoreQueryFilters().SingleOrDefaultAsync(x=>x.TenantId==tenant&&x.EventId==eventId&&x.Id==itemId,ct);if(item is null)return Missing();var latest=await _db.EventOfflineSyncDecisions.IgnoreQueryFilters().Where(x=>x.TenantId==tenant&&x.ItemId==itemId).OrderByDescending(x=>x.DecisionVersion).FirstAsync(ct);var kh=Hash(key);var replay=await _db.EventOfflineSyncDecisions.IgnoreQueryFilters().SingleOrDefaultAsync(x=>x.TenantId==tenant&&x.ResolutionIdempotencyHash==kh,ct);if(replay is not null){if(replay.ItemId!=itemId)return Conflict("EVENT_CHECKIN_IDEMPOTENCY_CONFLICT");await tx.CommitAsync(ct);return await ConflictsAsync(tenant,eventId,actor,1,ct);}if(latest.DecisionVersion!=expectedDecision||latest.Outcome!="conflict")return Conflict();var before=await AttendanceVersion(tenant,eventId,item.UserId,ct);if(before!=expectedAttendance)return Conflict();long? after=null,activity=null;var outcome="rejected";var code="manual_rejected";if(disposition=="apply"){var applied=await ApplyAttendance(tenant,eventId,actor,item,"offline-resolution:"+key,ct);if(!applied.Ok)return Conflict(applied.Code!);after=applied.After;activity=applied.Activity;outcome="accepted";code="manual_applied";}var next=new EventOfflineSyncDecision{TenantId=tenant,EventId=eventId,BatchId=item.BatchId,ItemId=item.Id,DecisionVersion=latest.DecisionVersion+1,Outcome=outcome,Code=code,Reason=clean,AttendanceVersionBefore=before,AttendanceVersionAfter=after,AttendanceActivityId=activity,DecidedByUserId=actor,ResolutionIdempotencyHash=kh};_db.Add(next);await _db.SaveChangesAsync(ct);await tx.CommitAsync(ct);return await ConflictsAsync(tenant,eventId,actor,1,ct);}
    public async Task<EventOfflineResult> ScanAsync(int tenant,int eventId,int actor,string deviceSecret,string token,string operation,long expected,string key,string? reason,CancellationToken ct)
    {var valid=ValidKey(key);if(valid is not null)return valid;if(!Operations.Contains(operation)||expected<0)return Validation("action");if(await DeviceBySecret(tenant,eventId,deviceSecret,ct) is null)return UnauthorizedDevice();if(string.IsNullOrWhiteSpace(token))return Missing("EVENT_CHECKIN_CREDENTIAL_INVALID");var hash=Hash(token);var cred=await _db.EventCheckinCredentials.IgnoreQueryFilters().SingleOrDefaultAsync(x=>x.TenantId==tenant&&x.EventId==eventId&&x.TokenFingerprint==hash.Substring(0,16),ct);if(cred is null||!CryptographicOperations.FixedTimeEquals(Convert.FromHexString(cred.TokenHash),Convert.FromHexString(hash))||cred.Status!="active"||cred.ExpiresAt<=DateTime.UtcNow)return Missing("EVENT_CHECKIN_CREDENTIAL_INVALID");var c=await Context(tenant,eventId,actor,true,ct);if(!c.Succeeded)return c;var item=new EventOfflineSyncItem{TenantId=tenant,EventId=eventId,UserId=cred.UserId,RegistrationId=cred.RegistrationId,CredentialId=cred.Id,Operation=operation,ExpectedAttendanceVersion=expected,Reason=Clean(reason,500)};await using var tx=await _db.Database.BeginTransactionAsync(ct);await Lock(tenant,eventId,ct);var applied=await ApplyAttendance(tenant,eventId,actor,item,key,ct);if(!applied.Ok)return Conflict(applied.Code!);await tx.CommitAsync(ct);return new(new{contract_version=1,event_id=eventId,state="synced",attendance=new{user_id=cred.UserId,state=applied.State,version=applied.After},privacy=new{credential_redacted=true,wallet_effects_supported=false}});}

    private async Task<Dictionary<string,EventCheckinCredential>> ResolveCredentialSubjects(int tenant,int eventId,IEnumerable<EventOfflineSyncItem> items,DateTime evaluatedAt,CancellationToken ct)
    {
        var fingerprints=items.Select(x=>x.CredentialFingerprint).Distinct(StringComparer.Ordinal).ToArray();
        var credentials=await _db.EventCheckinCredentials.IgnoreQueryFilters().AsNoTracking().Where(x=>x.TenantId==tenant&&x.EventId==eventId&&fingerprints.Contains(x.TokenFingerprint)).ToListAsync(ct);
        var byFingerprint=credentials.GroupBy(x=>x.TokenFingerprint,StringComparer.Ordinal).ToDictionary(x=>x.Key,x=>x.Single(),StringComparer.Ordinal);
        foreach(var item in items)
        {
            if(!byFingerprint.TryGetValue(item.CredentialFingerprint,out var credential)||!IsUsableCredential(item,credential,evaluatedAt))continue;
