    private async Task DecideInitial(int tenant,int eventId,int actor,EventOfflineSyncItem item,EventCheckinCredential? cred,DateTime credentialEvaluatedAt,CancellationToken ct)
    {
        string outcome,code;long before=await AttendanceVersion(tenant,eventId,cred?.UserId,ct);long? after=null,activity=null;
        if(!IsUsableCredential(item,cred,credentialEvaluatedAt)||item.CredentialId!=cred!.Id||item.RegistrationId!=cred.RegistrationId||item.UserId!=cred.UserId){outcome="rejected";code="credential_invalid";}
        else if(before!=item.ExpectedAttendanceVersion){outcome="conflict";code="attendance_version_conflict";}
        else
        {
            var applied=await ApplyAttendance(tenant,eventId,actor,item,$"offline:{item.DeviceId}:{item.ClientNonce}",ct);
            if(applied.Ok){outcome="accepted";code="synced";after=applied.After;activity=applied.Activity;}else{outcome="conflict";code=applied.Code!;}
        }
        _db.Add(new EventOfflineSyncDecision{TenantId=tenant,EventId=eventId,BatchId=item.BatchId,ItemId=item.Id,Outcome=outcome,Code=code,AttendanceVersionBefore=before,AttendanceVersionAfter=after,AttendanceActivityId=activity,DecidedByUserId=actor});await _db.SaveChangesAsync(ct);
    }
    private static bool IsUsableCredential(EventOfflineSyncItem item,EventCheckinCredential? credential,DateTime evaluatedAt)=>credential is not null&&credential.TokenHash==item.CredentialHashReference&&credential.Status=="active"&&credential.ExpiresAt>evaluatedAt;
    private async Task<(bool Ok,string? Code,long After,long? Activity,string State,bool Replay)> ApplyAttendance(int tenant,int eventId,int actor,EventOfflineSyncItem item,string key,CancellationToken ct){var existing=await _db.EventAttendanceActivity.IgnoreQueryFilters().AsNoTracking().SingleOrDefaultAsync(x=>x.TenantId==tenant&&x.IdempotencyKey==key,ct);if(existing is not null)return(true,null,existing.AttendanceVersion,existing.Id,existing.ToStatus,true);if(item.UserId is not int user)return(false,"credential_invalid",0,null,"",false);var fact=await _db.EventAttendance.IgnoreQueryFilters().SingleOrDefaultAsync(x=>x.TenantId==tenant&&x.EventId==eventId&&x.UserId==user,ct);var before=fact?.AttendanceVersion??0;if(before!=item.ExpectedAttendanceVersion)return(false,"attendance_version_conflict",before,null,fact?.AttendanceStatus??"not_checked_in",false);var from=fact?.AttendanceStatus??"not_checked_in";var to=item.Operation switch{"check_in" when from is "not_checked_in" or "no_show"=>"checked_in","check_out" when from=="checked_in"=>"checked_out","no_show" when from=="not_checked_in"=>"no_show","undo" when from is "checked_in" or "checked_out" or "no_show"=>"not_checked_in",_=>null};if(to is null)return(false,"attendance_transition_invalid",before,null,from,false);var now=DateTime.UtcNow;if(fact is null){fact=new EventAttendance{TenantId=tenant,EventId=eventId,UserId=user,AttendanceVersion=1,AttendanceStatus=to,StatusChangedAt=now,StatusChangedBy=actor};_db.Add(fact);}else{fact.AttendanceVersion++;fact.AttendanceStatus=to;fact.StatusChangedAt=now;fact.StatusChangedBy=actor;fact.UpdatedAt=now;}if(to=="checked_in"){fact.CheckedInAt=now;fact.CheckedInBy=actor;fact.CheckedOutAt=null;}else if(to=="checked_out")fact.CheckedOutAt=now;else if(to=="not_checked_in"){fact.CheckedInAt=null;fact.CheckedInBy=null;fact.CheckedOutAt=null;}await _db.SaveChangesAsync(ct);var activity=new EventAttendanceActivity{TenantId=tenant,EventId=eventId,AttendanceId=fact.Id,UserId=user,ActorUserId=actor,AttendanceVersion=fact.AttendanceVersion,Action=item.Operation,FromStatus=from,ToStatus=to,IdempotencyKey=key,Reason=item.Reason,Metadata=JsonSerializer.Serialize(new{source="offline_checkin"})};_db.Add(activity);await _db.SaveChangesAsync(ct);return(true,null,fact.AttendanceVersion,activity.Id,to,false);}
    private IQueryable<ConflictJoin> OpenQuery(int tenant,int eventId)=>from i in _db.EventOfflineSyncItems.IgnoreQueryFilters() join b in _db.EventOfflineSyncBatches.IgnoreQueryFilters() on i.BatchId equals b.Id join d in _db.EventOfflineSyncDecisions.IgnoreQueryFilters() on i.Id equals d.ItemId where i.TenantId==tenant&&i.EventId==eventId&&d.Outcome=="conflict"&&!_db.EventOfflineSyncDecisions.IgnoreQueryFilters().Any(n=>n.TenantId==tenant&&n.ItemId==i.Id&&n.DecisionVersion>d.DecisionVersion) select new ConflictJoin(i,b,d);
    private async Task<EventOfflineResult> Context(int tenant,int eventId,int actor,bool manager,CancellationToken ct){var e=await _db.Events.IgnoreQueryFilters().SingleOrDefaultAsync(x=>x.TenantId==tenant&&x.Id==eventId,ct);if(e is null)return Missing();var u=await _db.Users.IgnoreQueryFilters().AsNoTracking().SingleOrDefaultAsync(x=>x.TenantId==tenant&&x.Id==actor&&x.IsActive,ct);if(u is null)return Forbidden();if(manager&&!await CanManage(tenant,e,actor,ct))return Forbidden();return new(e);}
    private async Task<bool> CanManage(int tenant,Event e,int actor,CancellationToken ct){var u=await _db.Users.IgnoreQueryFilters().AsNoTracking().SingleAsync(x=>x.TenantId==tenant&&x.Id==actor,ct);if(IsAdmin(u)||e.CreatedById==actor)return true;return await _db.EventStaffAssignments.IgnoreQueryFilters().AnyAsync(x=>x.TenantId==tenant&&x.EventId==e.Id&&x.UserId==actor&&x.Status=="active"&&(x.ExpiresAt==null||x.ExpiresAt>DateTime.UtcNow)&&(x.Role=="check_in_staff"||x.Role=="event_manager"||x.Role=="co_organizer"),ct);}
    private Task<EventRegistration?> ConfirmedRegistration(int t,int e,int u,CancellationToken ct)=>_db.EventRegistrations.IgnoreQueryFilters().SingleOrDefaultAsync(x=>x.TenantId==t&&x.EventId==e&&x.UserId==u&&x.RegistrationState=="confirmed",ct);
    private async Task<EventCheckinDevice?> DeviceBySecret(int t,int e,string secret,CancellationToken ct){if(!Regex.IsMatch(secret,"^nxd1_[A-Za-z0-9_-]{43}$"))return null;var hash=Hash(secret);return await _db.EventCheckinDevices.IgnoreQueryFilters().SingleOrDefaultAsync(x=>x.TenantId==t&&x.EventId==e&&x.SecretFingerprint==hash.Substring(0,16)&&x.SecretHash==hash&&x.Status=="active"&&x.ExpiresAt>DateTime.UtcNow,ct);}
    private Task Lock(int t,int e,CancellationToken ct)=>_db.Database.ExecuteSqlInterpolatedAsync($"SELECT pg_advisory_xact_lock({t}, {e})",ct);private async Task<long> AttendanceVersion(int t,int e,int? u,CancellationToken ct)=>u is null?0:await _db.EventAttendance.IgnoreQueryFilters().Where(x=>x.TenantId==t&&x.EventId==e&&x.UserId==u).Select(x=>(long?)x.AttendanceVersion).SingleOrDefaultAsync(ct)??0;
    private EventOfflineResult BatchResult(int eventId,EventOfflineSyncBatch b,IEnumerable<EventOfflineSyncItem> items,IEnumerable<EventOfflineSyncDecision> decisions)=>new(new{contract_version=1,event_id=eventId,batch=new{id=b.Id,client_batch_id=b.ClientBatchId,status=b.Status,item_count=b.ItemCount,accepted_count=b.AcceptedCount,conflict_count=b.ConflictCount,rejected_count=b.RejectedCount,created_at=Iso(b.CreatedAt),completed_at=IsoN(b.CompletedAt)},items=items.Select(i=>{var d=decisions.Where(x=>x.ItemId==i.Id).OrderByDescending(x=>x.DecisionVersion).FirstOrDefault();return new{id=i.Id,position=i.Position,client_nonce=i.ClientNonce,operation=i.Operation,observed_at=Iso(i.ObservedAt),expected_attendance_version=i.ExpectedAttendanceVersion,state=d?.Outcome switch{"accepted"=>"synced","conflict"=>"conflict","rejected"=>"rejected",_=>"pending"},decision_version=(int?)d?.DecisionVersion,code=d?.Code,reason=d?.Reason??i.Reason,decided_at=IsoN(d?.DecidedAt)};}),privacy=new{credential_redacted=true,attendee_identity_redacted=true}});
    private EventOfflineResult ConflictResult(int eventId,IEnumerable<ConflictJoin> rows,int total,int page,Dictionary<int,User> users,Dictionary<long,EventCheckinDevice> devices,Dictionary<int,EventAttendance> attendance)=>new(new{contract_version=1,event_id=eventId,items=rows.Select(x=>new{item_id=x.Item.Id,batch_id=x.Batch.Id,client_batch_id=x.Batch.ClientBatchId,member=new{id=x.Item.UserId!.Value,display_name=users.TryGetValue(x.Item.UserId.Value,out var u)?Name(u):""},operation=x.Item.Operation,observed_at=Iso(x.Item.ObservedAt),submitted_reason=x.Item.Reason,expected_attendance_version=x.Item.ExpectedAttendanceVersion,current_attendance=new{state=attendance.TryGetValue(x.Item.UserId.Value,out var a)?a.AttendanceStatus:"not_checked_in",version=attendance.TryGetValue(x.Item.UserId.Value,out a)?a.AttendanceVersion:0},conflict=new{decision_version=x.Decision.DecisionVersion,code=x.Decision.Code!,decided_at=Iso(x.Decision.DecidedAt)},device=new{id=x.Batch.DeviceId,label=devices.TryGetValue(x.Batch.DeviceId,out var d)?d.Label:null}}),total,page,per_page=25,privacy=new{credential_redacted=true,contact_fields_redacted=true,free_text_member_profile_redacted=true}});
